#!/usr/bin/env python3
"""Mesh Lifecycle and Topology CLI Tool."""

import argparse
import json
import sys
from dataclasses import dataclass, field
from enum import Enum
from pathlib import Path
from typing import Any, Optional

import yaml

# In-memory storage for meshes (simulating persistence)
MEShes: dict[str, 'Mesh'] = {}


class ConditionType(str, Enum):
    HEALTHY = "Healthy"
    PRECHECKS_PASSED = "PrechecksPassed"
    SCALING = "Scaling"
    GRACEFUL_SHUTDOWN = "GracefulShutdown"


@dataclass
class Condition:
    type: str
    status: str  # "True" or "False"
    message: str = ""

    def to_dict(self) -> dict:
        return {
            "type": self.type,
            "status": self.status,
            "message": self.message,
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Condition':
        return cls(
            type=data["type"],
            status=data["status"],
            message=data.get("message", ""),
        )


@dataclass
class StorageSpec:
    size: Optional[str] = None
    ephemeral: bool = False
    className: Optional[str] = None

    def to_dict(self) -> dict:
        result = {"ephemeral": self.ephemeral}
        if not self.ephemeral:
            result["size"] = self.size
        if self.className is not None:
            result["className"] = self.className
        return result

    @classmethod
    def from_dict(cls, data: dict) -> 'StorageSpec':
        return cls(
            size=data.get("size"),
            ephemeral=data.get("ephemeral", False),
            className=data.get("className"),
        )


@dataclass
class NetworkSpec:
    storage: Optional[StorageSpec] = None
    replicationFactor: Optional[int] = None

    def to_dict(self) -> dict:
        result = {}
        if self.storage:
            result["storage"] = self.storage.to_dict()
        if self.replicationFactor is not None:
            result["replicationFactor"] = self.replicationFactor
        return result

    @classmethod
    def from_dict(cls, data: dict) -> 'NetworkSpec':
        storage = None
        if "storage" in data:
            storage = StorageSpec.from_dict(data["storage"])
        return cls(
            storage=storage,
            replicationFactor=data.get("replicationFactor"),
        )


@dataclass
class Spec:
    instances: Optional[int] = None
    network: Optional[NetworkSpec] = None

    def to_dict(self) -> dict:
        result = {}
        if self.instances is not None:
            result["instances"] = self.instances
        if self.network:
            result["network"] = self.network.to_dict()
        return result

    @classmethod
    def from_dict(cls, data: dict) -> 'Spec':
        network = None
        if "network" in data:
            network = NetworkSpec.from_dict(data["network"])
        return cls(
            instances=data.get("instances"),
            network=network,
        )


@dataclass
class InstancesStatus:
    ready: int = 0
    starting: int = 0
    stopped: int = 0

    def to_dict(self) -> dict:
        return {
            "ready": self.ready,
            "starting": self.starting,
            "stopped": self.stopped,
        }


@dataclass
class Metadata:
    name: str

    def to_dict(self) -> dict:
        return {"name": self.name}

    @classmethod
    def from_dict(cls, data: dict) -> 'Metadata':
        return cls(name=data["name"])


@dataclass
class Status:
    state: str = "Running"
    stable: bool = True
    instances: InstancesStatus = field(default_factory=InstancesStatus)
    conditions: list[Condition] = field(default_factory=list)
    desiredInstancesOnResume: Optional[int] = None

    def to_dict(self) -> dict:
        result = {
            "state": self.state,
            "stable": self.stable,
            "instances": self.instances.to_dict(),
            "conditions": [c.to_dict() for c in sorted(self.conditions, key=lambda c: c.type)],
        }
        if self.desiredInstancesOnResume is not None:
            result["desiredInstancesOnResume"] = self.desiredInstancesOnResume
        return result


@dataclass
class Mesh:
    apiVersion: str = "mesh.example.com/v1"
    kind: str = "Mesh"
    metadata: Metadata = field(default_factory=lambda: Metadata(name=""))
    spec: Spec = field(default_factory=Spec)
    status: Status = field(default_factory=lambda: Status())

    def to_dict(self) -> dict:
        return {
            "apiVersion": self.apiVersion,
            "kind": self.kind,
            "metadata": self.metadata.to_dict(),
            "spec": self.spec.to_dict(),
            "status": self.status.to_dict(),
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Mesh':
        return cls(
            apiVersion=data.get("apiVersion", "mesh.example.com/v1"),
            kind=data.get("kind", "Mesh"),
            metadata=Metadata.from_dict(data["metadata"]),
            spec=Spec.from_dict(data.get("spec", {})),
            status=Status.from_dict(data.get("status", {})),
        )


def validate_size(size: str) -> bool:
    """Validate memory quantity format."""
    if not size:
        return False
    # Check if it's a non-negative integer
    if size.isdigit():
        return int(size) >= 0
    # Check if it's a non-negative integer with unit
    import re
    match = re.match(r'^(\d+)(Ki|Mi|Gi|Ti)$', size)
    if match:
        return int(match.group(1)) >= 0
    return False


def validate_replication_factor(value: int, instances: int) -> list[dict]:
    """Validate replication factor. Returns list of errors."""
    errors = []
    if value < 1:
        errors.append({
            "field": "spec.network.replicationFactor",
            "type": "invalid",
            "message": f"value '{value}' must be at least 1",
        })
    if value > instances:
        errors.append({
            "field": "spec.network.replicationFactor",
            "type": "invalid",
            "message": f"value '{value}' must not exceed spec.instances ({instances})",
        })
    return errors


def validate_storage_size(size: str) -> list[dict]:
    """Validate storage size."""
    errors = []
    if not validate_size(size):
        errors.append({
            "field": "spec.network.storage.size",
            "type": "invalid",
            "message": f"value '{size}' is not a valid memory quantity",
        })
    return errors


def merge_conditions(existing: list[Condition], updates: list[Condition]) -> list[Condition]:
    """Merge conditions, respecting uniqueness and ordering."""
    # Create a map of condition types to conditions
    condition_map = {c.type: c for c in existing}

    # Apply updates
    for cond in updates:
        condition_map[cond.type] = cond
        if cond.message == "" and cond.status == "False":
            # Remove condition if it's False with empty message (clearing it)
            del condition_map[cond.type]

    # Sort by type ascending
    result = sorted(condition_map.values(), key=lambda c: c.type)
    return result


def create_mesh(data: dict) -> tuple[Optional[dict], list[dict]]:
    """Create a new mesh from YAML data. Returns (mesh_dict, errors)."""
    errors = []

    # Validate metadata.name
    if "metadata" not in data or "name" not in data["metadata"]:
        errors.append({
            "field": "metadata.name",
            "type": "required",
            "message": "metadata.name is required",
        })
        return None, errors

    name = data["metadata"]["name"]

    # Check if mesh already exists
    if name in MEShes:
        errors.append({
            "field": "metadata.name",
            "type": "already_exists",
            "message": f"mesh '{name}' already exists",
        })
        return None, errors

    # Parse spec
    spec_data = data.get("spec", {})

    # Validate instances if present
    instances = spec_data.get("instances")
    if instances is not None:
        if not isinstance(instances, int) or instances < 0:
            errors.append({
                "field": "spec.instances",
                "type": "invalid",
                "message": f"value '{instances}' must be a non-negative integer",
            })
        # Validate replication factor against instances if both are provided
        if errors and instances >= 0:
            network = spec_data.get("network", {})
            rf = network.get("replicationFactor")
            if rf is not None:
                errors.extend(validate_replication_factor(rf, instances))

    # Validate storage size if present
    network = spec_data.get("network", {})
    storage = network.get("storage", {})
    if "size" in storage:
        errors.extend(validate_storage_size(storage["size"]))
    else:
        # Default size to "1Gi" when omitted
        storage["size"] = "1Gi"

    # Set default replication factor if not provided and instances > 0
    if instances and instances > 0 and "replicationFactor" not in network:
        network["replicationFactor"] = instances

    if errors:
        return None, errors

    # Create mesh object
    mesh_data = {
        "apiVersion": data.get("apiVersion", "mesh.example.com/v1"),
        "kind": data.get("kind", "Mesh"),
        "metadata": {"name": name},
        "spec": {
            "instances": instances,
            "network": {
                "storage": {
                    "size": storage["size"],
                    "ephemeral": storage.get("ephemeral", False),
                },
            },
        },
    }

    # Add className if present
    if "className" in storage and storage["className"] is not None:
        mesh_data["spec"]["network"]["storage"]["className"] = storage["className"]

    # Add replication factor
    if "replicationFactor" in network:
        mesh_data["spec"]["network"]["replicationFactor"] = network["replicationFactor"]

    # Remove network if empty
    if not mesh_data["spec"]["network"]["storage"] and "replicationFactor" not in mesh_data["spec"]["network"]:
        del mesh_data["spec"]["network"]
    if not mesh_data["spec"]["network"]:
        del mesh_data["spec"]["network"]

    mesh = Mesh.from_dict(mesh_data)

    # Set initial status
    if instances and instances > 0:
        mesh.status.state = "Running"
        mesh.status.instances.ready = instances
        mesh.status.instances.starting = 0
        mesh.status.instances.stopped = 0
    else:
        mesh.status.state = "Stopped"
        mesh.status.instances.ready = 0
        mesh.status.instances.starting = 0
        mesh.status.instances.stopped = 0

    # Add initial conditions
    mesh.status.conditions = [
        Condition(type="Healthy", status="True", message=""),
        Condition(type="PrechecksPassed", status="True", message=""),
    ]

    # Store mesh
    MEShes[name] = mesh

    return mesh.to_dict(), []


def list_meshes() -> list[dict]:
    """List all mesh summaries."""
    result = []
    for mesh in MEShes.values():
        result.append({
            "apiVersion": mesh.apiVersion,
            "kind": mesh.kind,
            "metadata": {"name": mesh.metadata.name},
            "spec": {
                "instances": mesh.spec.instances,
            },
            "status": {
                "state": mesh.status.state,
                "stable": mesh.status.stable,
                "instances": mesh.status.instances.to_dict(),
            },
        })
    return result


def describe_mesh(name: str) -> tuple[Optional[dict], list[dict]]:
    """Describe a specific mesh."""
    if name not in MEShes:
        return None, [{
            "field": "metadata.name",
            "type": "not_found",
            "message": f"mesh '{name}' not found",
        }]

    mesh = MEShes[name]

    # Handle transient conditions (e.g., Scaling) - omit on describe
    conditions = [c for c in mesh.status.conditions
                  if not (c.type == "Scaling" and c.status == "True")]
    mesh.status.conditions = conditions

    return mesh.to_dict(), []


def delete_mesh(name: str) -> tuple[Optional[dict], list[dict]]:
    """Delete a mesh."""
    if name not in MEShes:
        return None, [{
            "field": "metadata.name",
            "type": "not_found",
            "message": f"mesh '{name}' not found",
        }]

    mesh = MEShes.pop(name)
    return mesh.to_dict(), []


def update_mesh(data: dict) -> tuple[Optional[dict], list[dict]]:
    """Apply a partial update to a mesh."""
    errors = []

    # Validate metadata.name
    if "metadata" not in data or "name" not in data["metadata"]:
        errors.append({
            "field": "metadata.name",
            "type": "required",
            "message": "metadata.name is required",
        })
        return None, errors

    name = data["metadata"]["name"]

    # Check if mesh exists
    if name not in MEShes:
        errors.append({
            "field": "metadata.name",
            "type": "not_found",
            "message": f"mesh '{name}' not found",
        })
        return None, errors

    mesh = MEShes[name]
    old_instances = mesh.spec.instances if mesh.spec.instances else 0
    old_state = mesh.status.state
    old_stopped = mesh.status.instances.stopped

    # Track if we need to add transient conditions
    add_scaling = False
    scaling_message = ""
    add_graceful_shutdown = False

    # Process updates field by field (merge rules)
    update_spec = data.get("spec", {})

    # Handle instances update
    if "instances" in update_spec:
        new_instances = update_spec["instances"]

        if not isinstance(new_instances, int) or new_instances < 0:
            errors.append({
                "field": "spec.instances",
                "type": "invalid",
                "message": f"value '{new_instances}' must be a non-negative integer",
            })
        else:
            # Check for stop (positive to 0)
            if old_instances > 0 and new_instances == 0:
                add_graceful_shutdown = True
                mesh.status.state = "Stopped"
                mesh.status.instances.ready = 0
                mesh.status.instances.starting = 0
                mesh.status.instances.stopped = old_instances
                mesh.status.desiredInstancesOnResume = old_instances
                mesh.status.stable = False
            # Check for scale up (0 to positive or increase)
            elif old_instances == 0 and new_instances > 0 and mesh.status.desiredInstancesOnResume is not None:
                # Resume case
                mesh.status.desiredInstancesOnResume = None
                add_scaling = True
                scaling_message = "Resuming mesh"
                mesh.status.instances.ready = 0
                mesh.status.instances.starting = new_instances
                mesh.status.instances.stopped = 0
                mesh.status.state = "Running"
                mesh.status.stable = False
            elif new_instances > old_instances:
                # Scale up
                add_scaling = True
                scaling_message = f"Scaling from {old_instances} to {new_instances} instances"
                mesh.status.instances.ready = old_instances
                mesh.status.instances.starting = new_instances - old_instances
                mesh.status.stable = False
            elif new_instances < old_instances:
                # Scale down
                add_scaling = True
                scaling_message = ""
                mesh.status.instances.ready = new_instances
                mesh.status.instances.starting = 0
                mesh.status.instances.stopped = old_instances - new_instances
                mesh.status.stable = False

            # Update spec instances
            mesh.spec.instances = new_instances

    # Handle network updates
    if "network" in update_spec:
        update_network = update_spec["network"]

        # Handle storage updates
        if "storage" in update_network:
            update_storage = update_network["storage"]
            current_storage = mesh.spec.network.storage if mesh.spec.network else None

            # Create storage if it doesn't exist
            if not current_storage:
                current_storage = StorageSpec()
                if not mesh.spec.network:
                    mesh.spec.network = NetworkSpec()
                mesh.spec.network.storage = current_storage

            # Check for immutable size changes
            if "size" in update_storage and current_storage.size is not None:
                if update_storage["size"] != current_storage.size:
                    errors.append({
                        "field": "spec.network.storage.size",
                        "type": "immutable",
                        "message": f"field 'spec.network.storage.size' is immutable after creation",
                    })
            else:
                # Apply updates
                if "size" in update_storage:
                    current_storage.size = update_storage["size"]
                if "ephemeral" in update_storage:
                    current_storage.ephemeral = update_storage["ephemeral"]
                if "className" in update_storage:
                    current_storage.className = update_storage["className"]

        # Handle replicationFactor updates
        if "replicationFactor" in update_network:
            new_rf = update_network["replicationFactor"]
            current_instances = mesh.spec.instances if mesh.spec.instances else 0

            if new_rf < 1:
                errors.append({
                    "field": "spec.network.replicationFactor",
                    "type": "invalid",
                    "message": f"value '{new_rf}' must be at least 1",
                })
            elif new_rf > current_instances:
                errors.append({
                    "field": "spec.network.replicationFactor",
                    "type": "invalid",
                    "message": f"value '{new_rf}' must not exceed spec.instances ({current_instances})",
                })
            else:
                if not mesh.spec.network:
                    mesh.spec.network = NetworkSpec()
                mesh.spec.network.replicationFactor = new_rf

    if errors:
        return None, errors

    # Apply transient conditions
    if add_scaling:
        # Remove existing Scaling condition if present
        mesh.status.conditions = [c for c in mesh.status.conditions if c.type != "Scaling"]
        mesh.status.conditions.append(Condition(type="Scaling", status="True", message=scaling_message))
        mesh.status.stable = False

    if add_graceful_shutdown:
        mesh.status.conditions.append(Condition(type="GracefulShutdown", status="True", message=""))
        mesh.status.stable = False

    # Ensure stable is correct
    if not add_scaling and not add_graceful_shutdown:
        mesh.status.stable = True

    return mesh.to_dict(), []


def load_yaml_file(path: str) -> dict:
    """Load YAML from file."""
    with open(path, 'r') as f:
        return yaml.safe_load(f)


def main():
    parser = argparse.ArgumentParser(description="Mesh Lifecycle and Topology CLI")
    subparsers = parser.add_subparsers(dest="command", help="Commands")

    # Mesh commands
    mesh_parser = subparsers.add_parser("mesh", help="Mesh operations")
    mesh_subparsers = mesh_parser.add_subparsers(dest="mesh_command", help="Mesh commands")

    # mesh create
    create_parser = mesh_subparsers.add_parser("create", help="Create a mesh")
    create_parser.add_argument("-f", "--file", required=True, help="YAML file path")

    # mesh list
    mesh_subparsers.add_parser("list", help="List meshes")

    # mesh describe
    describe_parser = mesh_subparsers.add_parser("describe", help="Describe a mesh")
    describe_parser.add_argument("name", help="Mesh name")

    # mesh delete
    delete_parser = mesh_subparsers.add_parser("delete", help="Delete a mesh")
    delete_parser.add_argument("name", help="Mesh name")

    # mesh update
    update_parser = mesh_subparsers.add_parser("update", help="Update a mesh")
    update_parser.add_argument("-f", "--file", required=True, help="YAML file path")

    args = parser.parse_args()

    if args.command != "mesh" or args.mesh_command is None:
        parser.print_help()
        sys.exit(1)

    if args.mesh_command == "create":
        data = load_yaml_file(args.file)
        result, errors = create_mesh(data)
        if errors:
            print(json.dumps({"errors": errors}, indent=2))
            sys.exit(1)
        print(json.dumps(result, indent=2))

    elif args.mesh_command == "list":
        result = list_meshes()
        print(json.dumps(result, indent=2))

    elif args.mesh_command == "describe":
        result, errors = describe_mesh(args.name)
        if errors:
            print(json.dumps({"errors": errors}, indent=2))
            sys.exit(1)
        print(json.dumps(result, indent=2))

    elif args.mesh_command == "delete":
        result, errors = delete_mesh(args.name)
        if errors:
            print(json.dumps({"errors": errors}, indent=2))
            sys.exit(1)
        print(json.dumps(result, indent=2))

    elif args.mesh_command == "update":
        data = load_yaml_file(args.file)
        result, errors = update_mesh(data)
        if errors:
            print(json.dumps({"errors": errors}, indent=2))
            sys.exit(1)
        print(json.dumps(result, indent=2))


if __name__ == "__main__":
    main()

