    """Create a new mesh from YAML data."""
    errors = []

    # Validate metadata.name
    if "metadata" not in data or "name" not in data["metadata"]:
        errors.append({
            "field": "metadata.name",
            "type": "required",
            "message": "metadata.name is required",
        })
        return None, errors

    name = data["metadata"]["name"]

    # Check if mesh already exists
    if name in MEShes:
        errors.append({
            "field": "metadata.name",
            "type": "already_exists",
            "message": f"mesh '{name}' already exists",
        })
        return None, errors

    # Parse spec
    spec = data.get("spec", {})
    instances = spec.get("instances")

