            mesh["spec"]["network"]["replicationFactor"] = network["replicationFactor"]

    # Set initial instances status
    if instances and instances > 0:
        mesh["status"]["instances"]["ready"] = instances

    # Store mesh
    MEShes[name] = mesh

    return mesh, []


