    """List mesh summaries."""
    result = []
    for name in sorted(MEShes.keys()):
        mesh = MEShes[name]
        result.append({
            "apiVersion": mesh["apiVersion"],
            "kind": mesh["kind"],
            "metadata": {"name": mesh["metadata"]["name"]},
