#!/usr/bin/env python3
"""Mesh Lifecycle and Topology CLI Tool."""

import argparse
import json
import re
import sys
from enum import Enum
from typing import Any, Optional

# Simple YAML parser for the expected format
# Supports: mappings, sequences, scalars (strings, numbers, booleans)

def parse_simple_yaml(content: str) -> dict:
    """Parse a simple YAML format."""
    lines = content.split('\n')
    result = {}
    stack = [(result, 0)]  # (current_dict, indent_level)

    for line in lines:
        if not line.strip() or line.strip().startswith('#'):
            continue

        # Count indentation
        indent = 0
        stripped = line
        for char in line:
            if char == ' ':
                indent += 1
            else:
                break
        stripped = line.strip()

        # Get key and value
        if ':' not in stripped:
            continue

        key_part, _, value_part = stripped.partition(':')
        key = key_part.strip()
        value = value_part.strip()

        # Find the right parent in stack
        while stack and stack[-1][1] >= indent:
            stack.pop()

        if not stack:
            continue

        parent, _ = stack[-1]

        if value:
            # Simple key: value
            # Parse value
            parsed_value = parse_scalar(value)
            parent[key] = parsed_value
        else:
            # Nested mapping
            new_dict = {}
            parent[key] = new_dict
            stack.append((new_dict, indent))

    return result


def parse_scalar(value: str) -> Any:
    """Parse a scalar value."""
    # Boolean
    if value.lower() == 'true':
        return True
    if value.lower() == 'false':
        return False
    # Null
    if value.lower() in ('null', '~', ''):
        return None
    # Integer
    if re.match(r'^-?\d+$', value):
        try:
            return int(value)
        except ValueError:
            pass
    # String
    return value.strip('"').strip("'")


def load_yaml_file(path: str) -> dict:
    """Load YAML from file."""
    with open(path, 'r') as f:
        content = f.read()
    try:
        # Try with yaml first
        import yaml
