def update_mesh(data: dict) -> tuple[Optional[dict], list[dict]]:
    """Apply a partial update to a mesh."""
    errors = []

    # Validate metadata.name
    if data is None or not isinstance(data, dict):
        errors.append({
            "field": "metadata.name",
            "type": "required",
            "message": "metadata.name is required",
        })
