                sys.exit(1)
            print(json.dumps(result, indent=2))

        elif args.mesh_command == "delete":
            result, errors = delete_mesh(args.name)
            if errors:
                print(json.dumps({"errors": errors}, indent=2))
                sys.exit(1)
            print(json.dumps(result, indent=2))

        elif args.mesh_command == "update":
