    """Test condition sorting and uniqueness."""
    conditions = [
        {"type": "Zebra", "status": "True"},
        {"type": "Apple", "status": "False"},
        {"type": "Zebra", "status": "True"},  # Duplicate - should be removed
        {"type": "Banana", "status": "True"},
