    names = [m["metadata"]["name"] for m in result]
    assert names == ["test-list-0", "test-list-1", "test-list-2"]
    print("✓ test_list_meshes passed")


def test_scale_up():
    """Test scaling up (increasing instances)."""
    data = {
        "metadata": {"name": "test-scale-up"},
        "spec": {"instances": 2}
    }
    create_mesh(data)

    update_data = {
        "metadata": {"name": "test-scale-up"},
        "spec": {"instances": 5}
    }
